import torch
from torch import Tensor def prepare_whisper_vietnamese_training( audio_paths: list[str], transcriptions: list[str], max_duration_sec: float = 30.0, sample_rate: int = 16000,
) -> dict[str, list]: """Prepare training data for Whisper Vietnamese fine-tuning. Args: audio_paths: Paths to audio files transcriptions: Corresponding Vietnamese transcriptions max_duration_sec: Maximum audio duration sample_rate: Target sample rate Returns: dataset: Dictionary with processed examples """ # Vietnamese special considerations: # 1. Normalize Unicode (NFC normalization for diacritics) # 2. Handle tone marks consistently # 3. Lowercase (Vietnamese is case-sensitive for proper nouns) import unicodedata processed_texts: list[str] = [] for text in transcriptions: # NFC normalization, critical for Vietnamese diacritics normalized: str = unicodedata.normalize("NFC", text) processed_texts.append(normalized) # Whisper uses special tokens # <|startoftranscript|><|vi|><|transcribe|><|notimestamps|>...text...<|endoftext|> prefix_tokens: str = "<|startoftranscript|><|vi|><|transcribe|><|notimestamps|>" return { "audio_paths": audio_paths, "texts": processed_texts, "language": "vi", "task": "transcribe", } Approach 2: Wav2Vec 2.0 + CTC $$ \text{XLSR-53 (multilingual Wav2Vec 2.0)} \xrightarrow{\text{CTC fine-tune}} \text{Vietnamese ASR} $$ XLSR-53: Pre-trained on 56K hours, 53 languages Fine-tune với CTC loss trên Vietnamese data Character-level vocabulary (chữ cái + dấu thanh) Approach 3: Conformer + RNN-T (Production) $$ \text{Conformer Encoder} + \text{RNN-T Decoder} \xrightarrow{\text{Train from scratch}} \text{Streaming Vietnamese ASR} $$ Vietnamese WER Results Model Dataset WER Kaldi GMM-HMM [1] VIVOS 28.1% Wav2Vec 2.0 (XLSR fine-tune) VIVOS 9.8% Whisper Large-v3 VIVOS 8.2% Whisper Large-v3 (fine-tuned) VIVOS 5.1% Conformer-RNN-T (from scratch) Internal 1000h 4.5% : Vietnamese ASR results

